# Verify ASCII<->FEN for the two redone diagrams + example2
def fen_to_grid(board):
    rows=board.split('/')
    g=[]
    for r in rows:
        line=[]
        for ch in r:
            if ch.isdigit(): line+=['.']*int(ch)
            else: line.append(ch)
        g.append(line)
    return g
def show(fen):
    b=fen.split()[0]; g=fen_to_grid(b)
    for i,row in enumerate(g):
        print(8-i,' '.join(row))
